def _normalize_scores(raw_value):
    if isinstance(raw_value, list):
        values = raw_value
    elif isinstance(raw_value, dict):
        def _to_rank(item):
            key, _ = item
            try:
                return int(key)
            except (TypeError, ValueError):
                return 9999
        values = [value for _, value in sorted(raw_value.items(), key=_to_rank)]
    else:
        return []

    normalized = []
    for value in values:
        try:
            normalized.append(max(0, int(value)))
        except (TypeError, ValueError):
            continue
    return normalized


def _extract_ranked_entries(raw_value, id_key):
    entries = []
    if isinstance(raw_value, dict):
        iterable = raw_value.items()
    elif isinstance(raw_value, list):
        iterable = enumerate(raw_value, start=1)
    else:
        iterable = []

    for rank_source, payload in iterable:
        try:
            rank = int(rank_source)
        except (TypeError, ValueError):
            if isinstance(rank_source, int):
                rank = rank_source
            else:
                continue
        if rank <= 0:
            continue

        entry = {'rank': rank}
        if isinstance(payload, dict):
            target_id = payload.get(id_key)
            reason = payload.get('reason')
        else:
            target_id = payload
            reason = None

        try:
            target_id = int(target_id)
        except (TypeError, ValueError):
            continue

        entry[id_key] = target_id
        if isinstance(reason, str) and reason.strip():
            entry['reason'] = reason.strip()
        entries.append(entry)

    entries.sort(key=lambda item: item['rank'])
    return entries


def _resolve_group_id(group_model, db_alias, lesson_session_id, group_id=None, group_number=None):
    if group_id:
        return group_id
    if not group_number:
        return None
    group = group_model.objects.using(db_alias).filter(
        lesson_session_id=lesson_session_id,
        group_number=group_number,
    ).first()
    return group.id if group else None


